#include <bits/stdc++.h>using namespace std; void solve() {    long long n, q;    cin >> n >> q;    long long sum = 0;    vector<long long> a(n);    for (int i = 0; i < n; i++){         cin >> a[i];    }    sort(a.begin(), a.end());    int left = a[0];    int right = a[0] + q;    int ans = 0;    while(left <= right){        int mid = left + (right - left)/2;        long long sum = 0;        for(int i = 0; i < n; i++){            sum += max(0LL, mid - a[i]);        }        if(sum > q){            right = mid - 1;        }        else{            ans = mid;            left = mid + 1;        }    }        cout << ans << "\n";} int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int tt;    cin >> tt;    while(tt--)    solve();}